<?php ob_start(); $rows = $result['data'] ?? []; ?>
<?php if ($flash = session()->getFlash('error')): ?><div class="alert alert-danger"><?= sanitize($flash) ?></div><?php endif; ?>
<div class="card shadow-sm"><div class="card-header bg-white d-flex justify-content-between align-items-center"><h6 class="mb-0 fw-semibold"><i class="fas fa-cog me-2 text-primary"></i>Payroll Processing</h6></div><div class="card-body p-0"><table class="table table-hover mb-0"><thead class="table-light"><tr><th>Employee</th><th>Month/Year</th><th class="text-end">Gross</th><th class="text-end">Net</th><th>Status</th></tr></thead><tbody><?php if (empty($rows)): ?><tr><td colspan="5" class="text-center text-muted py-4">No payroll records found.</td></tr><?php else: ?><?php foreach ($rows as $p): ?><tr><td><?= sanitize($p['first_name'] . ' ' . $p['last_name']) ?></td><td><?= sanitize($p['month'] . '/' . $p['year']) ?></td><td class="text-end">৳<?= number_format((float) $p['gross_salary'], 2) ?></td><td class="text-end">৳<?= number_format((float) $p['net_salary'], 2) ?></td><td><span class="badge bg-secondary"><?= ucfirst(sanitize($p['status'])) ?></span></td></tr><?php endforeach; ?><?php endif; ?></tbody></table></div></div>
<?php $content = ob_get_clean(); include __DIR__ . '/../../layouts/app.php'; ?>
